import clsx from "clsx";

type StepHeroProps = {
  stepLabel: string;
  title: string;
  subtitle: string;
  imageSrc: string;
  imageAlt: string;
  className?: string;
};

export function StepHero({
  stepLabel,
  title,
  subtitle,
  imageSrc,
  imageAlt,
  className,
}: StepHeroProps) {
  return (
    <>
      {/* Mobile: unchanged typographic block */}
      <div className={clsx("d-page-meta md:hidden", className)}>
        <span className="d-step-label">{stepLabel}</span>
        <h1 className="planner-page-title">{title}</h1>
        <p className="planner-page-sub">{subtitle}</p>
      </div>

      {/* Desktop: grid + image */}
      <div className="mb-6 mt-0 hidden md:grid md:grid-cols-2 md:items-center md:gap-6">
        <div>
          <span className="text-xs font-semibold uppercase tracking-wide text-blue-600">
            {stepLabel}
          </span>
          <h1 className="mt-1 text-2xl font-semibold text-gray-900">{title}</h1>
          <p className="mt-1 text-sm text-gray-500">{subtitle}</p>
        </div>
        <div className="h-28 w-full overflow-hidden rounded-xl shadow-sm ring-1 ring-gray-200/80">
          <img
            src={imageSrc}
            alt={imageAlt}
            className="h-full w-full object-cover"
            loading="lazy"
          />
        </div>
      </div>
    </>
  );
}
